X******************************************************************/
X
Xtypedef int lockhandle_t;
X
Xconst char	*const *Argv;
X
Xpid_t		Session_gpid;
X
Xconst char	*Logfile = "logfile";
X
Xvolatile int	Hang_up;
X
X/******************************************************************
X******************************************************************/
X
Xvoid lock_handle( lockhandle_t handle, const char *datei )
X{
X	int		st;
X
X	if ( datei == NULL )
X		return;
X
X	/* CONSTANTCONDITION */
X	while ( 1 ) {
X		st = flock( handle, LOCK_EX | LOCK_NB );
X		if ( st == 0 )
X			break;
X		if ( errno == EWOULDBLOCK ) {
X			printf( "blocked by <%s>\n", datei );
X			break;
X		};
X		fprintf( stderr,
X			"lock <%s> returns %d: %s", datei, st,
X			strerror( errno ) );
X		if ( errno == ENOLCK ) {
X			sleep( 20 );
X			continue;
X		};
X		return;
X	};
X	/* CONSTANTCONDITION */
X	while ( 1 ) {
X		st = flock( handle, LOCK_EX );
X		if ( st == 0 )
X			break;
X		fprintf( stderr,
X			"lock <%s> returns %d: %s", datei, st,
X			strerror( errno ) );
X		if ( errno == ENOLCK ) {
X			sleep( 20 );
X			continue;
X		};
X		return;
X	}
X}
X
X/******************************************************************
X******************************************************************/
X
XFILE *file_open( const char *datei, const char *mode )
X{
X	FILE *handle;
X
X	if ( datei == NULL )
X		return ( NULL );
X
X	handle = fopen( datei, mode );
X	if ( handle == NULL )
X		fprintf( stderr,
X			"Fatal: Datei '%s' nicht verfuegbar", datei );
X	if ( mode[ 0 ] != 'r' )
X		lock_handle( fileno( handle ), datei );
X	return ( handle );
X}
X
Xvoid file_close( FILE *handle )
X{
X	int		status;
X
X	status = fclose( handle );
X	if ( status != 0 ) {
X		fprintf( stderr,
X			"Fatal: Fehler %d beim Schliessen der Datei",
X			status );
X	}
X}
X
X/******************************************************************
X******************************************************************/
X
X#ifdef __FreeBSD__
X#undef SIG_DFL
X#define SIG_DFL		(void (*)(int))0
X#undef SIG_IGN
X#define SIG_IGN		(void (*)(int))1
X#endif
X
Xvoid my_appl_exit( void );
Xvoid my_appl_exit( void )
X{
X	signal( SIGHUP, SIG_DFL );
X	signal( SIGQUIT, SIG_DFL );
X}
X
Xvoid onquit( int test );
X/* ARGSUSED */
Xvoid onquit( int test )
X{
X	fprintf( stderr, "QUIT-Signal\n" );
X	signal( SIGQUIT, onquit );
X
X	signal( SIGHUP, SIG_IGN );
X	signal( SIGTERM, SIG_IGN );
X	if ( Session_gpid > 1 )
X		(void)kill( -Session_gpid, SIGHUP );
X	if ( Session_gpid > 1 )
X		(void)kill( -Session_gpid, SIGTERM );
X	my_appl_exit();
X	execv( Argv[ 0 ], (char *const *)Argv );
X}
X
Xvoid onhangup( int test );
X/* ARGSUSED */
Xvoid onhangup( int test )
X{
X	FILE *flog;
X
X	fprintf( stderr, "HANGUP-Signal\n" );
X	if ( Hang_up == 0 ) {
X		signal( SIGHUP, SIG_IGN );
X		if ( Session_gpid > 1 ) {
X			(void)kill( -Session_gpid, SIGHUP );
X		}
X	};
X	Hang_up = 1;
X	signal( SIGHUP, onhangup );
X
X	/* deadlock */
X	flog = file_open( Logfile, "ab" );
X	file_close( flog );
X}
X
Xvoid my_appl_init( void );
Xvoid my_appl_init( void )
X{
X#ifdef __FreeBSD__
X	int error;
X#endif
X
X	atexit( my_appl_exit );
X#ifdef __FreeBSD__
X	error = setpgid( 0, getppid() );
X	if ( error < 0 ) {
X		fprintf( stderr,
X				"!!! Fehler %d in "
X				"'setpgid( ppid=%ld )' :%s",
X				error, (long)getppid(),
X				strerror( errno ) );
X	};
X	Session_gpid = setsid();
X	if ( Session_gpid < (pid_t)0 ) {
X		fprintf( stderr,
X				"!!! Fehler %d in "
X				"'setsid()' :%s", error,
X				strerror( errno ) );
X	};
X#else
X	Session_gpid = 0;
X#endif
X	signal( SIGHUP, onhangup );
X	signal( SIGQUIT, onquit );
X}
X
Xvoid main( int argc, const char *const *argv );
Xvoid main( int argc, const char *const *argv )
X{
X	FILE *flog;
X
X	Hang_up = 0;
X	Argv = argv;
X	my_appl_init();
X	flog = file_open( Logfile, "ab" );
X	fputs( "main\n", flog );
X	while ( Hang_up == 0 )
X		;
X	file_close( flog );
X	exit( 0 );
X}
